import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class SecurePathTraversalExample {

    public static void main(String[] args) {
        String userInput = "../importantFile.txt";
        String directory = "/home/user/files/";

        try {
            File file = Paths.get(directory, userInput).normalize().toFile();

            if (!file.getAbsolutePath().startsWith(directory)) {
                System.err.println("Invalid file path provided.");
                return;
            }

            FileInputStream fis = new FileInputStream(file);

            int data;
            while ((data = fis.read()) != -1) {
                System.out.print((char) data);
            }

            fis.close();
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
    }
}

